    private void jbnAgregarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jbnAgregarActionPerformed
        // TODO add your handling code here:
        String tipo = cmbTipo.getSelectedItem().toString();
        String descripcion = JtaDescripcion.getText().trim();

        if (descripcion.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Por favor, describe la incidencia.");
            return;
        }

        Controlador.ControladorIncidencias control = new Controlador.ControladorIncidencias();

        if (control.registrarIncidencia(this.idActividadRef, tipo, descripcion, userSesion.getIdUsuario(), this.idUbicacionRef)) {
            JOptionPane.showMessageDialog(this, "¡Incidencia reportada con éxito!");

            MisActividades reporte = new MisActividades(userSesion);
            reporte.setVisible(true);
            this.dispose();
        } else {
            JOptionPane.showMessageDialog(this, "Error al registrar la incidencia. Revisa la consola.");
        }
    }//GEN-LAST:event_jbnAgregarActionPerformed

