    private void JtaDescripcionKeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_JtaDescripcionKeyPressed
        // TODO add your handling code here:
        char tecla = (char) evt.getExtendedKeyCode();
        if (tecla == KeyEvent.VK_ENTER) {
            jbnAgregar.requestFocus();
        }
    }//GEN-LAST:event_JtaDescripcionKeyPressed

    private void jbnAgregarKeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_jbnAgregarKeyPressed
        // TODO add your handling code here:
        char tecla = (char) evt.getExtendedKeyCode();
        if (tecla == KeyEvent.VK_ENTER) {
        jbnAgregar.doClick();
        jbnRegresar.requestFocus();
        }
    }//GEN-LAST:event_jbnAgregarKeyPressed

    private void jbnRegresarKeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_jbnRegresarKeyPressed
        // TODO add your handling code here:
        char tecla = (char) evt.getExtendedKeyCode();
        if (tecla == KeyEvent.VK_ENTER) {
            jbnRegresar.doClick();
        }
    }//GEN-LAST:event_jbnRegresarKeyPressed

